const TZ = 'Indian/Antananarivo';
const date = new Intl.DateTimeFormat('en-CA', {
  timeZone: TZ,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(new Date());

function asList(nodeName) {
  try {
    const items = $(nodeName).all();
    if (!items.length) return [];
    if (items.length === 1 && Array.isArray(items[0].json)) return items[0].json;
    if (items.length === 1 && items[0].json?.error) return [];
    const rows = items.map((i) => i.json).filter((j) => j && typeof j === 'object' && j.id != null);
    return rows.length ? rows : [];
  } catch {
    return [];
  }
}

function asObject(nodeName) {
  try {
    const j = $(nodeName).first().json;
    if (!j || j.error) return {};
    return j;
  } catch {
    return {};
  }
}

const matin = asObject('TWIY message matin');
const streaks = asList('Lire les streaks');
const quetes = asList('Lire les quêtes');
const emploi = asObject('Emploi du temps');

const actives = quetes.filter(
  (q) => ['dev', 'beatmaker'].includes(q.type) && q.statut !== 'fait' && q.statut !== 'abandonne',
);
const dev = actives.filter((q) => q.type === 'dev');
const beat = actives.filter((q) => q.type === 'beatmaker');

function lineQuete(q) {
  const due = q.date_prevue ? ` · prévu ${q.date_prevue}` : '';
  return `- [${q.statut}] ${q.titre || q.id}${due}`;
}

function lineStreak(s) {
  const risque = s.dernier_jour !== date ? " ⚠ pas alimenté aujourd'hui" : '';
  return `- **${s.id}** : ${s.jours_consecutifs ?? 0} j (record ${s.record ?? 0})${risque}`;
}

let contreBlock = matin.message || '—';
const contre = matin.contremaitre;
if (contre?.ressource_titre) {
  contreBlock += `\n\nSuggestion : ${contre.ressource_titre}` + (contre.ressource_url ? ` → ${contre.ressource_url}` : '');
}

let emploiBlock = '_non disponible_';
if (emploi.slots || emploi.bloc_actuel) {
  const lines = [];
  if (emploi.bloc_actuel) lines.push(`Bloc actuel : **${emploi.bloc_actuel}**`);
  const risques = emploi.streaks_a_risque || [];
  if (risques.length) {
    lines.push(`Streaks à risque : ${risques.map((r) => r.id || r).join(', ')}`);
  }
  for (const s of emploi.slots || []) {
    const actions = (s.actions || []).map((a) => a.titre || a).join(', ') || '—';
    lines.push(`- **${s.id || s.focus}**${s.focus ? ` (${s.focus})` : ''} : ${actions}`);
  }
  if (emploi.note_contexte) lines.push(`\n_Note : ${emploi.note_contexte}_`);
  emploiBlock = lines.join('\n') || '_vide_';
}

const md = `# Check-in matin — ${date}\n\n> Claude Pro lit cette note — ouvrir ou coller dans le chat pour le briefing du jour.\n\n## Streaks\n${streaks.length ? streaks.map(lineStreak).join('\n') : '_aucun_'}\n\n## Quêtes actives — Dev\n${dev.length ? dev.map(lineQuete).join('\n') : '_aucune_'}\n\n## Quêtes actives — Beatmaker\n${beat.length ? beat.map(lineQuete).join('\n') : '_aucune_'}\n\n## Contremaître\n${contreBlock}\n\n## Emploi du temps\n${emploiBlock}\n\n## LA chose ce soir\n\n**Quelle est LA chose à faire ce soir ?**\n`;

return [{ json: { date, markdown: md, ok: true } }];
